css_template:
#{{ID}} .na-zywo-wrapper {
    display: inline-flex;
    flex-direction: column;
    align-items: stretch;
    transform-origin: center center;
    opacity: 0;
    transform: {{ANIMATION_IN_TRANSFORM}};
    transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
    box-shadow: {{BOX_SHADOW}};
    border-radius: 4px;
    overflow: hidden;
}
#{{ID}} .na-zywo-container {
    display: inline-flex;
    align-items: center;
    background: {{PRIMARY_BG}};
    padding: 8px 16px;
    border-radius: 4px;
    font-family: '{{FONT_FAMILY}}', 'Arial', sans-serif;
}

#{{ID}} .na-zywo-text {
    color: {{TITLE_COLOR}};
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    letter-spacing: 1px;
    text-transform: uppercase;
}

js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector(".na-zywo-wrapper");
    root.__slt_show = () => {
        const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}});
        const textTl = GSAPFX.applyTextEffect(root, {{{TEXT_ANIM_JSON}}});
        if (textTl) {
            if ({{{TEXT_ANIM_SYNC}}}) {
                tl.add(textTl, ">-0.1");
            } else {
                tl.add(textTl, 0);
            }
        }
        return tl;
    };
    root.__slt_hide = () => {
        const textTl = GSAPFX.applyTextOutEffect(root, {{{TEXT_ANIM_OUT_JSON}}});
        const tl = GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}});
        if (textTl) {
            const sync = {{{TEXT_ANIM_OUT_SYNC}}};
            if (sync) {
                const combined = gsap.timeline();
                combined.add(textTl);
                combined.add(tl, ">-0.1");
                return combined;
            } else {
                tl.add(textTl, 0);
            }
        }
        return tl;
    };
})();
